window.__QUIZ_DATA__=[{"id":"objective>Geography>2005>1","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The scale of the map i representative fraction is","images":["data:image/png;base64,"],"options":{"A":"1:25,000","B":"1:50,000","C":"1:100,000","D":"1:200,000"},"answer":"C","explanation":"1cm rep 1km  =1cm to (1km \u22c6 100,000)  =1cm to 100,00cm   \u2234 1100,000  =1:100,000","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>2","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The direction of ohewo from ipiga is","images":["data:image/png;base64,"],"options":{"A":"North-East","B":"South-west","C":"North-west","D":"South-East"},"answer":"B","explanation":"From the map,  The direction of Ohewo from Ipiga is South-West.This is because the direction of Ipiga from Ohewo is North-East.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2005>3","subject":"Geography","year":"2005","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Which of the following is a confluence town ?","images":["data:image/png;base64,"],"options":{"A":"ohewo","B":"oju","C":"ipoya","D":"ipiga"},"answer":"B","explanation":"Oju is a confluence town which is located around the meeting point of two rivers which are River Suna and River Pam. Oju is a confluence town in Adum district.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>4","subject":"Geography","year":"2005","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Which of the following crop is likely to be cultivated in the area liabke to flooding ?","images":["data:image/png;base64,"],"options":{"A":"Rice","B":"yam","C":"cocoa","D":"Groundnut"},"answer":"A","explanation":"Rice is a popular cereal grown in the area liable to flooding. Rice can be planted by broadcasting,sowing or drilling of the seeds at 2-4cm deep.  Rice is cultivated in area liable to flooding.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2005>5","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The features market X can be described as","images":["data:image/png;base64,"],"options":{"A":"an on-bow lake","B":"meander","C":"a spur","D":"a col"},"answer":"B","explanation":"The feature X in the map in a Meander. This is the winding course or curve that develops along the course or curve that develops along the course or curve that develops along the course of the river. It is found at the middle or lower course of a river.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>6","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The direction of flow of river pam is","images":["data:image/png;base64,"],"options":{"A":"North-west","B":"North-East","C":"south-west","D":"south-east"},"answer":"D","explanation":"In the map,  River Pam flows south-east to Oju which is a confluence town that join River Pam and River Suna together.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2005>7","subject":"Geography","year":"2005","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"The likely occupation of the people in ipiga is","images":["data:image/png;base64,"],"options":{"A":"fishing","B":"farming","C":"mining","D":"lumbering"},"answer":"B","explanation":"In the map,                    Ipiga is an area filled with scattered cultivation and settlements which is suitable for Farming.Ipiga is located south-east of the map.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>8","subject":"Geography","year":"2005","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"The settlement of ipoya can be described as","images":["data:image/png;base64,"],"options":{"A":"linear","B":"clustered","C":"nucleated","D":"dispersed"},"answer":"A","explanation":"In the map,Ipiya is a linear settlement which buildings are located along the roads, railways or even rivers in a linear form.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>9","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The feature marked A-B can best be described as","images":["data:image/png;base64,"],"options":{"A":"concave slope","B":"scrap slope","C":"dip slope","D":"convex slope"},"answer":"A","explanation":"In the map,   The feature marked A-B is a concave slope which is a combination of both steep and gentle slopes and they are visible at bith ends.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>10","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : PRINCIPLES OF ELEMENTARY SURVEYING","question":"The bearing of ohewo from Adum is approximately","images":["data:image/png;base64,"],"options":{"A":"225\u2218","B":"265\u2218","C":"270\u2218","D":"275\u2218"},"answer":"A","explanation":"From the map, The bearing of Ohewo from Adum is approximately \"225\u2218 because it is located around the North-east of Ohewo.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2005>11","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"month J F M A M J J A S O N DTemperature 22 22 23 24 28 30 31 31 29 30 24 24Rainfall (MM) 32.552.0 132 225 270 310 354 416 221 31.0 11 02.1    The annual range of temperature for the stations is","images":[],"options":{"A":"6\u2218C","B":"9\u2218C","C":"11\u2218C","D":"12\u2218C"},"answer":"B","explanation":"Annual range of temperature =Temperature of the hottest month - Temperature of the coldest month  Annual range of temperature =31\u2218c - 22 \u2218c = 9 \u2218c","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>12","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"month J F M A M J J A S O N DTemperature 22 22 23 24 28 30 31 31 29 30 24 24Rainfall (MM) 32.552.0 132 225 270 310 354 416 221 31.0 11 02.1  Which of the following pairs of weather instrument were used to collect the data for the station?","images":[],"options":{"A":"rain guage and an anemometer","B":"a wind vane and a the thermometer","C":"a thermometer and a rain gauge","D":"a barometer and a rain gauge"},"answer":"C","explanation":"Thermometer is an instrument used to measure the temperature of a place and Rainguage is also an instument used to measure rainfall and other forms of precipitation.These instrument are used to collect data for the station.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>13","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"What is the approximate distance of town  from the equator if it is locator on latitude","images":[],"options":{"A":"1555km","B":"1232km","C":"441 km","D":"42km"},"answer":"A","explanation":"Latitude of equator = 0 0+ 14 0=14 0                                  =1 0=111km                                     14 0=X                                       X=111 \u22c6 14                                          =1,555km.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>14","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"When a warm ocean current meets a cold ocean current , they produce","images":[],"options":{"A":"mist","B":"signal","C":"fog","D":"hail"},"answer":"B","explanation":"Like squall is when a warm ocean current meets a cold ocean current. Like squall are produced by warm ocean current meets a cold ocean current.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>15","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The distance of planet mercury from the sun is about ?","images":[],"options":{"A":"40 million km","B":"50 million km","C":"57 million km","D":"60 million km"},"answer":"C","explanation":"Mercury is the smallest, the hottest and the closest planet to the sun.Its distance from the sun is 57,600,000km (36,000,000 miles). It has no satelite.It has no satelite. It has a diameter of 4,800km.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>16","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The most distant planet from the sun is","images":[],"options":{"A":"neptune","B":"mars","C":"Earth","D":"Pluto"},"answer":"D","explanation":"Pluto is the coldest and the farthest planet from the sun. It distance from the sun is about 5,850,000,000km.It has no satellite. It has a diameter of 5,800km.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>17","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which of this is not a proof that earth is spherical","images":[],"options":{"A":"The circullar horizon","B":"sunrise and sunset","C":"varying lenght in day and night","D":"Driving poles on a level ground"},"answer":"C","explanation":"Varying lengths of day and night is a proof that the earth is spherical are:Sunrise and sunset, circumnavigation of the Earth,planetary bodies etc.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>18","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The latitudes which mark the limits of the apparent movement of the overhead  sun are","images":[],"options":{"A":"Tropic of  cancer and the Artic circle","B":"Artic and antartical circles","C":"Tropics of cancer and capricorn","D":"Equator and the artic circle"},"answer":"B","explanation":"Arctic circle is located 66 1/2 \u2218S overhead the sun. Arctic circle and Antarctic circle are the latitude which mark the limit of the apparent movement of the overhead sun.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2005>19","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Weathering erosion, transportation and deposition ar processes of","images":[],"options":{"A":"mass wasting","B":"valcanicity","C":"denudation","D":"exfoliation"},"answer":"C","explanation":"Denudation is the process of lowering and levelling of the earth surface by gradual breaking and wearing away of such earth's surface. Its processes include; Weathering, erosion, transportation and deposition.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>20","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Which of the following factors times not affect the salinity of the oceans?","images":[],"options":{"A":"Rate of evapouration","B":"Degree of water mixing by current","C":"amount of fresh water added by rain","D":"shape of the ocean floor"},"answer":"D","explanation":"Salinity of the ocean is defined as the degree of saltiness or concentration of salt solution in ocean and sea. Its factor affecting it include; The rate of evaporation, degree of water mixing by currents. Shape of the ocean floor is not a factor affecting it.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2005>21","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Six's thermmometer is used to measure","images":[],"options":{"A":"maximum temperature","B":"minimum temperature","C":"minimum and maximum temperature","D":"average temperature"},"answer":"C","explanation":"Six's thermometer is an instrument used to measure minimum and maximum temperatures of a place. It is commonly recorded in centigrade (\u2218C) or Fahrenheit (\u2218F)scale. It has both freezing and boiling point.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2005>22","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The maximum temperature recorded for station X in a particular day was 14\u2218C while the minimum temperature was -4\u2218C. the diurnal range of temperature for the day was","images":[],"options":{"A":"5\u2218C","B":"9\u2218C","C":"12\u2218C","D":"18\u2218C"},"answer":"D","explanation":"Diurnal range of temperature=Maximum temperature + minimum temperature of that day                                                  =140\u2218C + 4\u2218C                                                 =18\u2218C  \u2234Diurnal range of temperature was 18\u2218C of that day.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>23","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"''It is warm and dusty, originates from the sahara and reaches its lowest southward extend in january ''. this best described","images":[],"options":{"A":"Tropical maritime airmass","B":"tropical continental airmass","C":"south westlies","D":"Eqautorial easterlies"},"answer":"D","explanation":"Equatorial Easterlies are areas located from the sahara desert they are warm, sandy and dusty. It reaches its lowest southward extent in the month of January. It has less vegetation and low source of water.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>24","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Heavy rain fall are often associated with","images":[],"options":{"A":"cirrus clouds","B":"cumulonimbus clouds","C":"nimbostratus clouds","D":"alto-status clouds"},"answer":"B","explanation":"Cumulonimbus is a cloud of great vertical height. It is a black and white globular mass giving its different shape. It is also referred to as \"thunder cloud\" and brings conventional rain, accompanied by lighting and thunder and associated with heavy heavy rainfall.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2005>25","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Which of the following gases is most abundant in the atmosphere","images":[],"options":{"A":"oxygen","B":"hydrogen","C":"Argon","D":"nitrogen"},"answer":"D","explanation":"The atmosphere is the gaseous portion of the earth. It is a layer of gases surrounding the earth. Its density decreases progressively with elevation. It contain 78% of Nitrogen, 21% Oxygen, 0.03% carbondioxide and 0.97% rare or inert gases.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2005>26","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"marble , slate and gneiss are","images":[],"options":{"A":"metamorphic ocks","B":"sedimentary rocks","C":"plulonic  rocks","D":"volcanic rocks"},"answer":"A","explanation":"Metamorphic rocks are changed rocks. The rocks are formed from pre-existing igneous or sedimentary rocks which have been changed as a result of great heat and pressure. Examples include;Slate, marble, quartzite,gneis,schist and graphite.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>27","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Which of the following is not a process of wind erosion?","images":[],"options":{"A":"Abrasion","B":"Attition","C":"Hydraulic action","D":"Deflation"},"answer":"C","explanation":"Hydraulic actions is a process when fast moving waves force themselves into cracks and cavities within the base of the cliff under pressure and enlarge the cracks. It is a mechanism of wave erosion and not a process of wind erosion.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>28","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"compressional forces are mainly responsible for the formation of","images":[],"options":{"A":"fold mountains","B":"volcanic mountains and lava plateau","C":"residual mountains and plains","D":"block mountains"},"answer":"A","explanation":"Fold mountains are formed by large scale horizontal earth movement as a result of stress and compressional forces which cause expansion or contraction of some parts of the earth. Compressional forces are mainly responsible for the formation of fold mountains.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2005>29","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The instrument used for measuring the speed of wind is called","images":[],"options":{"A":"cup anemometer","B":"speedometer","C":"wind vane","D":"prismatic compass"},"answer":"A","explanation":"Cup anemometer consists of three or four semi-circular cups attached to the ends of horizontal spokes mounted on a high vertical spindle. It is an instrument used to measure the speed of wind.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2005>30","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Coastal erosion can be prevented by","images":[],"options":{"A":"increasing the volume of water i the ocean","B":"increasing the volume of water around the coast","C":"the stabilization of sandy and muddy beaches by coastal vegetation","D":"The removal of sandy and muddy beaches along the coast"},"answer":"C","explanation":"Coastal erosion is the washing away of water from the coast of beaches. It is prevented by the stabilization of sandy and muddy beaches by coastal vegetation which will hold the erosion.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>31","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"coastline washes by cold current normally have","images":[],"options":{"A":"high temperature","B":"scanty rainfall","C":"excessive rainfall","D":"moderates rainfall"},"answer":"B","explanation":"Coastlines washed by cold currents normally have scanty rainfall because cold current lower the temperature of the coast land which makes it have low or scanty amount of rainfall in it.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>32","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"A continetal shelf is economically important beacuse it","images":[],"options":{"A":"is a good fishing ground","B":"is a good for irrigation","C":"is very deep","D":"contains little salt"},"answer":"A","explanation":"The continental shelf is a shallow water zone surrounding the continent. It contain minerals, rich in planktons, less than 250m deep. It has many economic importance like good fishing ground, sites for sporting activities, tourist centres etc.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>33","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"the most important action in the  A horizon of a soil profile is","images":[],"options":{"A":"eluviation","B":"deposition","C":"weathering","D":"illuviation"},"answer":"A","explanation":"Horizon is the top soil. It contain remains of plant and animals undergoing decomposition to form humus. It is also known as the eluviation zone. It is a zone of maximum biological activities of plants and soil micro-organism.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2005>34","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"All the following farming practices result in soil erosion except","images":[],"options":{"A":"Ploughing of land up and down slope","B":"Persistent cultivation of crops in regions of inadequate rainfall","C":"Over-cropping","D":"mixed cropping"},"answer":"D","explanation":"Soil erosion is the washing down of water from the uppermost layer of the earth. Mixed cropping is not a practices that result in soil erosion. Over-cropping, ploughing of land up and down slope are farm practices that result to soil erosion.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>35","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"which of the following feaures are associated with a river capture ?  I. misfit  II. River terraces  III. elbow of capture  IV. wind gap","images":[],"options":{"A":"I,II amd IV","B":"I,II, III and IV","C":"I,II, and IV","D":"II,III and IV"},"answer":"A","explanation":"River capture is formed when a river through headward erosion flows into a water divide and cut off the head water of another weaker river. Misfit river,river terraces, Elbow of capture are features associated with River capture or River piracy or River beheading.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2005>36","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Which of the following is not a method by which rivers transport their eroded materials?","images":[],"options":{"A":"suspension","B":"traction","C":"attrition","D":"solution"},"answer":"C","explanation":"The load of a river is carried or transported along the course of a river through four main processes. There are: Solution,Suspension,Saltation,Traction,Attrition is a process of river erosion not transportation.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>37","subject":"Geography","year":"2005","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Which of the following sea route carries the harviest traffic?","images":[],"options":{"A":"The suez canal zone","B":"The North Atlantic sea route","C":"The cape route","D":"The panama canal route"},"answer":"B","explanation":"The North Atlantic route is the busiest and the most important route that links two most populous and heavily industralised parts of the world i.e Western Europe and Eastern part of North America. About half of the world's major parts are located in this region.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>38","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The biosphere contains the following except","images":[],"options":{"A":"man","B":"rocks","C":"animals","D":"micro-organism"},"answer":"B","explanation":"Biosphere is the zone of the earth occupied by living organisms. It is a layer of life which exists on earth surface and the lithosphere. It includes organisms like plants, animals and micro-organisms. Rocks are not living organisms biosphere does not contain rocks.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2005>39","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Land and sea breeze a continetal scale are called","images":[],"options":{"A":"tupoons","B":"monsoons","C":"the fohn","D":"the chiinook"},"answer":"B","explanation":"Land and sea breeze are local winds which blow alternatively between land and sea on a daily basis. These breeze exchange between the land and the sea is attributed to differential heating of land and sea. On a continental scaled or is called Monsoons.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>40","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"The mediterranean type of climate is best suited for","images":[],"options":{"A":"cattle rearing","B":"fruit growing","C":"rice cultivation","D":"vegetables gardening"},"answer":"B","explanation":"Mediterranian type of climate is confined to western portion of continental masses between 30 \u2218 and 45 \u2218 north and south of the Equator. Wide range of fruits are grown, cultivation of grape fruits etc. It is suitable for fruit growing.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>41","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Which of the following vegetation types is associated with equitorial type of climate","images":[],"options":{"A":"Rain forest","B":"steppe","C":"montane","D":"pampas"},"answer":"A","explanation":"The sub-equatorial type of climate is associated with the rain forest is found or located around Equator. It has an annual rainfall of over 2000mm. It has rainfall throughout of the year with two peak (double maxima)","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>42","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Which of the following vegetation shows the correct sequence in food chain","images":[],"options":{"A":"Herbivores\u2192carnivores\u2192decompers\u2192plants","B":"carnivores\u2192decomposers\u2192herbivores\u2192plants","C":"plant \u2192 herbivores \u2192 carnivores \u2192decomposers","D":"decomposers\u2192herbivores \u2192 plants \u2192 carnivores"},"answer":"C","explanation":"Food chain is defined as the linkage of a series of organisms in a habitat through the flow of energy of consumer leads and their nutritional sequence. Examples of food chain are as follows.  Grass \u2190Sheep \u2190 Man.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2005>43","subject":"Geography","year":"2005","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"one of the major charateristics of heavy industries is that they","images":[],"options":{"A":"need low skilled man power","B":"are mainly concerntrated in the rural area","C":"need mainly female workers","D":"require high capital outlay"},"answer":"D","explanation":"Heavy industries are secondary industries. There products are heavy or bulky. It usually have scale in nature. Its employ the services of more males and it major characteristics require high capital outlay.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>44","subject":"Geography","year":"2005","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"A country is said to be land-locked when","images":[],"options":{"A":"she experiences a free flow of traffic","B":"her waterways are frozen in winter","C":"she experiences a lot of traffic congestions","D":"she has no direct access to the sea"},"answer":"D","explanation":"These are countries that do not have access to the ocean or coast. Examples of countries include Mali,Niger,Burkina faso, chad and so on. The country majorly does not a direct access to the sea.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>45","subject":"Geography","year":"2005","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Which of the following is a major hinderance to HEP production in Africa","images":[],"options":{"A":"inadequate capital","B":"unavailable of goods sites","C":"Absence of a domestic market","D":"sufficient volume of water"},"answer":"A","explanation":"Hydro electric power is electricity gotten from water. This is achieved through damming of rivers water to turn over turbines leading to the generation of electricity. Inadequate capital is an hindrance to H.E.P production in Africa.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>46","subject":"Geography","year":"2005","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"one advantage of in-land waterways is that","images":[],"options":{"A":"they are flexible","B":"they are fast","C":"goods are transported cheaply","D":"rivers at times, flow though area of limited commercial value"},"answer":"C","explanation":"Inland water-ways are located within an area in which water are being transported within an area. They are transported easily. Goods are also transported easily. Goods are also transported cheaply. This is a water transport which is very easy and flexible.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2005>47","subject":"Geography","year":"2005","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Which of the following is a demerit of low population density","images":[],"options":{"A":"low crime rate","B":"high per capita income","C":"inadequate labour force","D":"low pressure on social amenties"},"answer":"C","explanation":"Demerits of low population density are disadvantages of low population density which are inadequate labour force, low output, wastage of output, inadequate market, low defence, low revenue, low level of development etc.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2005>48","subject":"Geography","year":"2005","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"The most difficult problem facing lumbering in zaira is that the","images":[],"options":{"A":"wood are too hard and difficult to process","B":"log are too heavy to be moved to the saw mills","C":"ecconomic tress are not found in pure stand","D":"other countries are competiting with zaira in the lumbering activities"},"answer":"C","explanation":"Problems associated with the exploitation of timber in both Nigeria and Zaire are the same. These include; Economic trees are not found in pure strands, It also lead to the depletion of natural forest resources and also results in the leaching of the soil.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>49","subject":"Geography","year":"2005","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Which of the following vegetation types is found only in the northern hemisphere?","images":[],"options":{"A":"Tropical grassland","B":"equational forest","C":"tundra","D":"mediterrean"},"answer":"C","explanation":"Tundra vegetable are usually found in the Northern hemisphere. The natural vegetation includes mosses,lichens,tundra trees and shrubs. Other plant include crowberry, willow,birch,puppy and anemone.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2005>50","subject":"Geography","year":"2005","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"one effect of rural-urban migration on the source region is","images":[],"options":{"A":"rapid urbanization","B":"intensive pressure on land use in rural areas","C":"rural depopulation","D":"urban depopulation"},"answer":"C","explanation":"Rural-urban migration in the movement of people from rural areas e.g Village to urban centres like Ibadan, Lagos. It effects include Housing problem, Traffic congestions, High cost of living, Shortage of food in the urban areas e.t.c.","marks":"1","difficulty":"2"}];